'use client';

import { useState, useEffect, useRef } from 'react';
import { Search, Zap, Loader2, ExternalLink, Package, ShoppingCart } from 'lucide-react';
import { mockProducts } from '@/data/mockData';
import { DecisionCard } from '@/components/product/DecisionCard';
import { useRouter } from 'next/navigation';
import type { DecisionType, Product } from '@/types';

type FilterType = DecisionType | 'all';

const FILTERS: { id: FilterType; label: string; color?: string }[] = [
  { id: 'all',      label: '전체' },
  { id: 'buy',      label: '구매 추천',  color: 'text-decision-buy' },
  { id: 'wait',     label: '기다리세요', color: 'text-decision-wait' },
  { id: 'watch',    label: '지켜보세요', color: 'text-decision-watch' },
  { id: 'trending', label: '트렌딩',     color: 'text-decision-trending' },
];

interface NaverItem { title: string; price: number; mallName: string; link: string; image: string; }

export default function FeedPage() {
  const router = useRouter();
  const [activeFilter, setActiveFilter] = useState<FilterType>('all');
  const [searchQuery,  setSearchQuery]  = useState('');
  const [products,     setProducts]     = useState<Product[]>([]);
  const [loading,      setLoading]      = useState(true);
  const [useReal,      setUseReal]      = useState(false);

  // 검색어 입력 시 네이버 미리보기
  const [naverPreview,  setNaverPreview]  = useState<NaverItem[]>([]);
  const [naverSearching, setNaverSearching] = useState(false);
  const [showPreview, setShowPreview] = useState(false);
  const timerRef = useRef<ReturnType<typeof setTimeout>>();

  // DB 제품 로드
  useEffect(() => {
    async function load() {
      setLoading(true);
      try {
        const res = await fetch('/api/products?limit=30');
        if (res.ok) {
          const { products: data } = await res.json();
          if (data?.length > 0) { setProducts(data); setUseReal(true); return; }
        }
      } catch {}
      setProducts(mockProducts);
      setUseReal(false);
    }
    load().finally(() => setLoading(false));
  }, []);

  // 검색어 디바운스 → 네이버 미리보기
  useEffect(() => {
    if (!searchQuery.trim()) { setNaverPreview([]); return; }
    clearTimeout(timerRef.current);
    timerRef.current = setTimeout(async () => {
      setNaverSearching(true);
      try {
        const res = await fetch(`/api/price?query=${encodeURIComponent(searchQuery.trim())}&mode=search`);
        if (res.ok) {
          const data = await res.json();
          setNaverPreview((data.results ?? []).slice(0, 4));
        }
      } catch {}
      finally { setNaverSearching(false); }
    }, 400);
    return () => clearTimeout(timerRef.current);
  }, [searchQuery]);

  // DB 필터링 (로컬)
  const dbFiltered = products.filter(p => {
    const matchFilter = activeFilter === 'all' || p.decision === activeFilter;
    const matchSearch = !searchQuery.trim() ||
      p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      p.series.toLowerCase().includes(searchQuery.toLowerCase());
    return matchFilter && matchSearch;
  });

  return (
    <div className="p-6 lg:p-10 w-full">
      <div className="mb-8">
        <div className="flex items-center gap-3 mb-2">
          <Zap className="w-6 h-6 text-brand-500" />
          <h1 className="text-3xl font-bold text-white">구매 결정 피드</h1>
          {useReal && <span className="text-xs px-2 py-0.5 rounded-full bg-decision-buy/10 border border-decision-buy/20 text-decision-buy font-medium">실데이터</span>}
        </div>
        <p className="text-zinc-400 text-sm">실시간 시장 분석과 AI 구매 추천.</p>
      </div>

      {/* 필터 & 검색 */}
      <div className="flex flex-col lg:flex-row gap-4 justify-between items-start lg:items-center mb-8 bg-surface border border-surface-border p-4 rounded-xl">
        <div className="flex flex-wrap gap-2">
          {FILTERS.map(f => (
            <button key={f.id} onClick={() => setActiveFilter(f.id)}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                activeFilter === f.id
                  ? 'bg-surface-raised text-white border border-surface-border-light shadow-sm'
                  : `bg-transparent text-zinc-400 hover:bg-surface-raised/50 border border-transparent ${f.color ?? ''}`
              }`}>
              {f.label}
            </button>
          ))}
        </div>

        {/* 검색 — 네이버 미리보기 포함 */}
        <div className="relative w-full lg:w-72">
          <div className="relative">
            {naverSearching
              ? <Loader2 className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500 animate-spin" />
              : <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500" />}
            <input
              type="text"
              placeholder="제품명 검색 (네이버 연동)..."
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              onFocus={() => setShowPreview(true)}
              onBlur={() => setTimeout(() => setShowPreview(false), 150)}
              onKeyDown={e => {
                if (e.key === 'Enter' && searchQuery.trim()) {
                  router.push(`/search?q=${encodeURIComponent(searchQuery.trim())}`);
                }
              }}
              className="w-full bg-surface-base border border-surface-border rounded-lg pl-9 pr-4 py-2 text-sm text-white placeholder:text-zinc-600 focus:outline-none focus:border-brand-500 transition-all"
            />
          </div>

          {/* 네이버 미리보기 드롭다운 */}
          {showPreview && naverPreview.length > 0 && (
            <div className="absolute top-full left-0 right-0 mt-1 bg-surface-overlay border border-surface-border rounded-xl shadow-2xl shadow-black/50 overflow-hidden z-50">
              {naverPreview.map((item, i) => (
                <button key={i}
                  onMouseDown={() => router.push(`/product/naver?q=${encodeURIComponent(item.title)}&image=${encodeURIComponent(item.image)}`)}
                  className="w-full flex items-center gap-2 px-3 py-2.5 hover:bg-surface-raised transition-colors text-left border-b border-surface-border last:border-0">
                  {item.image
                    ? <img src={item.image} alt="" className="w-8 h-8 rounded object-contain bg-surface-raised shrink-0" />
                    : <Package className="w-8 h-8 text-zinc-700 shrink-0" />}
                  <div className="flex-1 min-w-0">
                    <p className="text-xs text-white truncate">{item.title}</p>
                    <p className="text-[10px] text-zinc-500">{item.mallName}</p>
                  </div>
                  {item.price >= 1000 && <span className="text-xs font-bold text-decision-buy shrink-0">{item.price.toLocaleString('ko-KR')}원</span>}
                </button>
              ))}
              <button
                onMouseDown={() => router.push(`/search?q=${encodeURIComponent(searchQuery.trim())}`)}
                className="w-full px-3 py-2 text-xs text-brand-400 hover:text-brand-300 text-right border-t border-surface-border">
                네이버 전체 검색 결과 보기 →
              </button>
            </div>
          )}
        </div>
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-24">
          <Loader2 className="w-5 h-5 animate-spin text-zinc-400 mr-3" />
          <span className="text-sm text-zinc-400">제품 로드 중...</span>
        </div>
      ) : dbFiltered.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
          {dbFiltered.map((product, i) => (
            <DecisionCard key={product.id} product={product} index={i} />
          ))}
        </div>
      ) : (
        <div className="text-center py-16 border border-surface-border border-dashed rounded-xl">
          <Search className="w-8 h-8 text-zinc-700 mx-auto mb-3" />
          <p className="text-zinc-500 text-sm mb-3">"{searchQuery}"에 대한 피드 결과가 없어요.</p>
          <button
            onClick={() => router.push(`/search?q=${encodeURIComponent(searchQuery)}`)}
            className="px-4 py-2 bg-brand-500/10 border border-brand-500/20 text-brand-400 rounded-lg text-sm font-medium hover:bg-brand-500/20 transition-colors flex items-center gap-2 mx-auto">
            <ShoppingCart className="w-4 h-4" />
            네이버에서 "{searchQuery}" 검색하기
          </button>
        </div>
      )}
    </div>
  );
}
